{
  "filecontent": null,
  "partialurl": "submit",
  "feedbackpolicy": 756150000,
  "excludefromsearch": false,
  "hiddenfromsitemap": false,
  "enablerating": false,
  "isroot": false,
  "sharedpageconfiguration": true,
  "parentpageid": "8860f327-aa0e-4946-bcba-adc8936b0d63",
  "publishingstateid": "499c599d-1425-4031-96b2-d329588ae104",
  "pagetemplateid": "a0e5f938-a922-f111-8342-000d3ab2c460",
  "isofflinecached": false,
  "rootwebpageid": "6bd606ce-0023-f111-8341-000d3ab2bd64",
  "copy": "<style>
  .priority-btn {
    border: 2px solid #d1d5db;
    /* gray border */
    border-radius: 6px;
    padding: 10px;
    cursor: pointer;
    transition: all 0.2s;
    background-color: #ffffff;
  }

  .priority-btn:hover {
    border-color: #2563eb;
    /* blue on hover */
  }

  .priority-btn.selected {
    border-color: #2563eb;
    /* highlight border */
    background-color: #bfdbfe;
    /* light blue background */
    color: #1d4ed8;
    /* dark blue text */
    font-weight: bold;
  }
</style>

<div class="hero hero--employee" style="padding:16px 16px 14px">
  <p class="hero-eyebrow hero-eyebrow--employee">New request</p>
  <h1>Submit a ticket</h1>
</div>

<div class="page-wrapper" id="pageWrapper">


  <main class="main">
    <div class="progress-row">
      <div class="progress-step done" id="step1">
        <div class="progress-num">&#10003;</div>Category
      </div>
      <div class="progress-line"></div>
      <div class="progress-step active" id="step2">
        <div class="progress-num">2</div>Issue details
      </div>
      <div class="progress-line"></div>
      <div class="progress-step" id="step3">
        <div class="progress-num">3</div>Priority
      </div>
      <div class="progress-line"></div>
      <div class="progress-step" id="step4">
        <div class="progress-num">4</div>Confirm
      </div>
    </div>

    <div class="card">
      <div class="card-head">
        <h3>Step 1 &mdash; Select category</h3>
      </div>
      <div class="category-grid">
        <div class="category-btn selected" value="0">
          <svg viewBox="0 0 16 16" fill="#1d4ed8">
            <path
              d="M3 2a1 1 0 00-1 1v10a1 1 0 001 1h10a1 1 0 001-1V3a1 1 0 00-1-1H3zm1 2h8v2H4V4zm0 3h3v5H4V7zm4 0h4v2H8V7z" />
          </svg>
          <p>Hardware</p>
        </div>
        <div class="category-btn" value="1">
          <svg viewBox="0 0 16 16" fill="#6b7280">
            <path
              d="M2 3a1 1 0 011-1h10a1 1 0 011 1v9a1 1 0 01-1 1H3a1 1 0 01-1-1V3zm1.5 1v7h9V4h-9zm1 1.5h7v1h-7v-1zm0 2.5h5v1H4.5V8z" />
          </svg>
          <p>Software</p>
        </div>
        <div class="category-btn" value="2">
          <svg viewBox="0 0 16 16" fill="#6b7280">
            <path
              d="M1 8a7 7 0 1114 0A7 7 0 011 8zm5-1h4v2H6V7zm-1-1a1 1 0 011-1h4a1 1 0 011 1v4a1 1 0 01-1 1H6a1 1 0 01-1-1V6z" />
          </svg>
          <p>Network</p>
        </div>
        <div class="category-btn" value="3">
          <svg viewBox="0 0 16 16" fill="#6b7280">
            <path d="M8 1a3.5 3.5 0 100 7 3.5 3.5 0 000-7zm-5 9.5a1 1 0 011-1h8a1 1 0 011 1V14H3v-3.5z" />
          </svg>
          <p>Access</p>
        </div>
      </div>
    </div>

    <div class="card">
      <div class="card-head">
        <h3>Step 2 &mdash; Describe the issue</h3>
      </div>
      <div class="form-group">
        <label for="ticket-title">Ticket title</label>
        <input type="text" id="ticket-title" placeholder="e.g. Laptop screen flickering on startup" required />
        <p class="form-hint">Be specific — a clear title helps IT agents resolve faster</p>
      </div>
      <div class="form-group">
        <label for="ticket-desc">Description</label>
        <textarea id="ticket-desc"
          placeholder="Describe the issue in detail. Include any error messages, steps to reproduce, and when it started..."></textarea>
      </div>
      <div class="field-row">
        <div class="form-group">
          <label for="ticket-device">Affected device / software</label>
          <input type="text" id="ticket-device" placeholder="e.g. Dell XPS 15, Microsoft Teams" />
        </div>
        <div class="form-group">
          <label for="ticket-date">When did it start?</label>
          <input type="date" id="ticket-date" />
        </div>
      </div>
    </div>

    <div class="card">
      <div class="card-head">
        <h3>Step 3 &mdash; Set priority</h3>
      </div>
      <div class="priority-grid">
        <div class="priority-btn priority-btn--low" value="0">
          <p>Low</p><span>Non-urgent, can wait</span>
        </div>
        <div class="priority-btn priority-btn--med" value="1">
          <p>Medium</p><span>Affecting work slightly</span>
        </div>
        <div class="priority-btn priority-btn--high" value="2">
          <p>High</p><span>Blocking my work</span>
        </div>
        <div class="priority-btn priority-btn--crit" value="3">
          <p>Critical</p><span>Entire team affected</span>
        </div>
      </div>
      <div class="btn-row">
        <button class="btn-primary" id="btnSubmit">Submit ticket</button>
        <button class="btn-secondary" onclick="window.location.href='home.html'">Cancel</button>
      </div>
    </div>
  </main>
</div>

<script src="https://code.jquery.com/jquery-3.6.0.min.js"></script>

<script>






  $(document).ready(function () {




    var ticketTitle, description, affectedDevice, ticketDate, category, priority;

    document.querySelectorAll('.category-btn').forEach(function (btn) {
      btn.addEventListener('click', function (e) {

        console.log('category: ', this.getAttribute('value'))
        // remove selected from all
        document.querySelectorAll('.category-btn').forEach(function (item) {
          item.classList.remove('selected');
        });

        // add selected to clicked one
        this.classList.add('selected');
        category = this.getAttribute('value');
      });
    });

    $('#ticket-title').on('input', function () {
      console.log($(this).val());

      ticketTitle = $(this).val();
      description = $('#ticket-desc').val();
      affectedDevice = $('#ticket-device').val();
      ticketDate = $('#ticket-date').val();

      if (ticketTitle != "" && description != "" && affectedDevice != "" && ticketDate != "") {
        // Mark step 1 as done (already has checkmark)
        document.getElementById("step1").classList.add("done");

        // Step 2 → done (remove active)
        let step2 = document.getElementById("step2");
        step2.classList.remove("active");
        step2.classList.add("done");

        // Replace the number "2" with a checkmark
        step2.querySelector(".progress-num").innerHTML = "&#10003;";

        // Step 3 → active
        document.getElementById("step3").classList.add("active");

      }

    });

    $('#ticket-desc').on('input', function () {

      description = $(this).val();
      ticketTitle = $('#ticket-title').val();
      affectedDevice = $('#ticket-device').val();
      ticketDate = $('#ticket-date').val();

      if (ticketTitle != "" && description != "" && affectedDevice != "" && ticketDate != "") {
        // Step 1 → done
        document.getElementById("step1").classList.add("done");

        // Step 2 → done (remove active)
        document.getElementById("step2").classList.remove("active");
        document.getElementById("step2").classList.add("done");

        // Replace the number "2" with a checkmark
        document.getElementById("step2").querySelector(".progress-num").innerHTML = "&#10003;";

        // Step 3 → active
        document.getElementById("step3").classList.add("active");

      }


    });

    $('#ticket-device').on('input', function () {

      affectedDevice = $(this).val();
      ticketTitle = $('#ticket-title').val();
      description = $('#ticket-desc').val();
      ticketDate = $('#ticket-date').val();

      if (ticketTitle != "" && description != "" && affectedDevice != "" && ticketDate != "") {
        // Step 1 → done
        document.getElementById("step1").classList.add("done");

        // Step 2 → done (remove active)
        document.getElementById("step2").classList.remove("active");
        document.getElementById("step2").classList.add("done");

        // Replace the number "2" with a checkmark
        document.getElementById("step2").querySelector(".progress-num").innerHTML = "&#10003;";

        // Step 3 → active
        document.getElementById("step3").classList.add("active");

      }


    });

    $('#ticket-date').on('input', function () {

      ticketDate = $(this).val();
      ticketTitle = $('#ticket-title').val();
      description = $('#ticket-desc').val();
      affectedDevice = $('#ticket-device').val();

      if (ticketTitle != "" && description != "" && affectedDevice != "" && ticketDate != "") {
        // Step 1 → done
        document.getElementById("step1").classList.add("done");

        // Step 2 → done (remove active)
        document.getElementById("step2").classList.remove("active");
        document.getElementById("step2").classList.add("done");

        // Replace the number "2" with a checkmark
        document.getElementById("step2").querySelector(".progress-num").innerHTML = "&#10003;";

        // Step 3 → active
        document.getElementById("step3").classList.add("active");

      }


    });

    // Select all priority buttons
    const priorityButtons = document.querySelectorAll('.priority-btn');

    priorityButtons.forEach(btn => {
      btn.addEventListener('click', () => {
        // Remove 'selected' class from all buttons
        priorityButtons.forEach(b => b.classList.remove('selected'));

        // Add 'selected' class to the clicked button
        btn.classList.add('selected');
        priority = document.querySelector('.priority-btn.selected').getAttribute('value');

        if (priority != "") {
          document.getElementById("step2").classList.add("done");

          // Step 2 → done (remove active)
          document.getElementById("step3").classList.remove("active");
          document.getElementById("step3").classList.add("done");

          // Replace the number "2" with a checkmark
          document.getElementById("step3").querySelector(".progress-num").innerHTML = "&#10003;";

          // Step 3 → active
          document.getElementById("step4").classList.add("active");
        }
      });
    });

    document.getElementById("btnSubmit").addEventListener("click", function () {

      var record = {};
      record.it_description = document.getElementById("ticket-desc").value;
      record.it_tickettitle = document.getElementById("ticket-title").value;
      record.it_affecteddevice = document.getElementById("ticket-device").value;
      record.it_startdate = document.getElementById("ticket-date").value;
      record.it_category = category;
      record.it_priority = priority;

      webapi.safeAjax({
        type: "POST",
        contentType: "application/json",
        url: "/_api/it_requests",
        data: JSON.stringify(record),
        success: function (data, textStatus, xhr) {
          var newId = xhr.getResponseHeader("entityid");
          console.log("***", newId);
          document.getElementById("step3").classList.add("done");

          // Step 2 → done (remove active)
          document.getElementById("step4").classList.remove("active");
          document.getElementById("step4").classList.add("done");

          // Replace the number "2" with a checkmark
          document.getElementById("step4").querySelector(".progress-num").innerHTML = "&#10003;";

          // Step 3 → active
          //  document.getElementById("step4").classList.add("active");
        },
        error: function (xhr, textStatus, errorThrown) {
          console.log(xhr);
        }
      });

    })


  })



</script>"
}
